  ('TOY_1KRFE_10', 'Toyota 1KR-FE 1.0L 3cyl', 'Toyota', 1.0, 3, 'petrol', 'chain', NULL, NULL, '0W-20 API SN', 3.2, 'Toyota Super Long Life Coolant (pink)', 'economy', 10000, 12, 'Yaris KSP90 1.0 2005-2010, Vitz KSP90/130 1.0, Aygo, Passo, Daihatsu Boon. Timing chain — quiet, reliable.'),
