  ('TOY_1NZFXE_15_HYBRID', 'Toyota 1NZ-FXE 1.5L Hybrid', 'Toyota', 1.5, 4, 'hybrid_petrol', 'chain', NULL, NULL, '0W-20 API SN', 3.7, 'Toyota Super Long Life Coolant (pink) + inverter coolant', 'hybrid', 10000, 12, 'Aqua NHP10 2011-2021 (NZ''s #1 hybrid import), Prius gen2 NHW20 2003-2009. Sterling Cars NZ data: 10-12yr / 220,000km pack life typical.'),
  ('TOY_1ZRFE_16', 'Toyota 1ZR-FE 1.6L', 'Toyota', 1.6, 4, 'petrol', 'chain', NULL, NULL, '5W-30 API SN', 4.2, 'Toyota Super Long Life Coolant (pink)', 'economy', 10000, 12, 'Corolla ZRE142 1.6, Auris ZRE151 1.6. Chain.'),
