  ('TOY_2ARFXE_25_HYBRID', 'Toyota 2AR-FXE 2.5L Hybrid', 'Toyota', 2.5, 4, 'hybrid_petrol', 'chain', NULL, NULL, '0W-20 API SN', 4.4, 'Toyota Super Long Life Coolant (pink) + inverter coolant', 'hybrid', 10000, 12, 'Camry hybrid AVV50/AXVH71, RAV4 hybrid AVA44 gen4, Lexus ES300h, NX300h.'),
  ('TOY_A25AFXS_25_HYBRID', 'Toyota A25A-FXS 2.5L Hybrid (TNGA)', 'Toyota', 2.5, 4, 'hybrid_petrol', 'chain', NULL, NULL, '0W-16 API SP', 4.5, 'Toyota Super Long Life Coolant (pink) + inverter coolant', 'hybrid', 10000, 12, 'RAV4 hybrid AXAH54 gen5 (TNGA, 2019+), Camry hybrid AXVH71, Harrier hybrid AXUH80, Lexus NX350h, ES300h facelift. Newer Li-ion HV pack.'),
  ('TOY_1KDFTV_30_DIESEL', 'Toyota 1KD-FTV 3.0L D-4D', 'Toyota', 3.0, 4, 'diesel', 'belt', 150000, 10, '5W-30 ACEA C2/C3 (Toyota 08880-83422)', 7.5, 'Toyota Super Long Life Coolant (pink)', 'mid', 10000, 12, 'Hilux KUN26 2005-2015, Prado KDJ150 2009-2015, Hiace KDH200/220 2004-2018, Land Cruiser 70-series. TIMING BELT — replace 150,000km. Famous for timing chain noise on 1KD is wrong — 1KD has a belt. 1GD-FTV that replaced it has a chain.'),
