  ('TOY_1GDFTV_28_DIESEL', 'Toyota 1GD-FTV 2.8L', 'Toyota', 2.8, 4, 'diesel', 'chain', NULL, NULL, '0W-30 or 5W-30 fully synthetic (Toyota 08880-83265)', 7.5, 'Toyota Super Long Life Coolant (pink)', 'mid', 10000, 12, 'Hilux GUN126 2015+, Prado GDJ150 2015+, Hiace GDH200/300, Fortuner. Timing chain — no scheduled replacement. DPF needs highway runs to regen. Some reports of chain rattle at 130,000km in heavy dust use.'),
  ('TOY_2GDFTV_24_DIESEL', 'Toyota 2GD-FTV 2.4L', 'Toyota', 2.4, 4, 'diesel', 'chain', NULL, NULL, '0W-30 or 5W-30 fully synthetic', 6.7, 'Toyota Super Long Life Coolant (pink)', 'mid', 10000, 12, 'Hilux GUN125 2.4 entry diesel 2015+, Fortuner 2.4. Detuned 1GD. Chain.'),
